settings.custom_liquid:
{% assign show_banner = false %}

{% for item in cart.items %}
  {% if item.product.tags contains "Bio-Lammfleisch" %}
    {% assign show_banner = true %}
  {% endif %}
{% endfor %}

{% if show_banner %}

<div class="weihnachts-banner page-width">
  <strong>
    Bitte wählen Sie einen Liefertermin. Die Lieferung Ihrer gesamten Bestellung erfolgt gesammelt zum gewählten Liefertermin des Bio-Lammfleisches.
  </strong>
</div>

<style>
.weihnachts-banner {
  background: #2d6c2b;
  color: white;
  padding: 12px 16px;
  border-radius: 8px;
  margin: 0 auto;
  font-size: 16px;
  line-height: 1.5;
  text-align: center;
  font-weight: 500;
  margin-top: -4rem;

}

.weihnachts-banner .weihnachts-link {
  display: inline-block;
  margin-top: 6px;
  color: #ffffff;
  background-color: #b68c37;
  padding: 8px 14px;
  border-radius: 5px;
  text-decoration: none;
  font-weight: 600;
  transition: background-color 0.3s ease;
}

.weihnachts-banner .weihnachts-link:hover {
  background-color: #b68c37;
}
</style>

{% endif %}
